// Etsy Receipt → orders-Schema transformieren
// Output 0: Bestellungen in erlaubten Währungen → upsert
// Output 1: Bestellungen in unerwarteten Währungen → Stop & Error

const ALLOWED_CURRENCIES = new Set(['EUR']);

const results = $input.all()[0]?.json.results ?? [];

const money = (obj) => obj ? (obj.amount / obj.divisor) : null;

const statusMap = {
  'paid':      'paid',
  'open':      'paid',
  'completed': 'completed',
  'shipped':   'shipped',
  'canceled':  'cancelled',
};

const expected  = [];
const unexpected = [];

for (const r of results) {
  const currency = r.currency_code ?? 'UNKNOWN';

  const items = (r.transactions ?? []).map(t => ({
    listing_id: t.listing_id,
    title:      t.title,
    quantity:   t.quantity,
    price:      money(t.price),
    is_digital: t.is_digital ?? false,
  }));

  const order = {
    json: {
      order_id:      String(r.receipt_id),
      source:        'etsy',
      order_date:    new Date(r.created_timestamp * 1000).toISOString(),
      buyer_name:    r.name ?? null,
      buyer_email:   r.buyer_email ?? null,
      buyer_street:  r.first_line ?? null,
      buyer_city:    r.city ?? null,
      buyer_zip:     r.zip ?? null,
      buyer_country: r.country_iso ?? null,
      items_json:    JSON.stringify(items),
      subtotal:      money(r.subtotal),
      shipping_cost: money(r.total_shipping_cost),
      total:         money(r.grandtotal),
      currency,
      status:        statusMap[r.status] ?? 'paid',
      is_digital:    items.every(i => i.is_digital),
    }
  };

  if (ALLOWED_CURRENCIES.has(currency)) {
    expected.push(order);
  } else {
    unexpected.push(order);
  }
}

return [expected, unexpected];

